# Category: insecure_jwt

import jwt
import json

def dump(token):
    try:
        decoded = jwt.decode(
            token=token,
            options={"verify": True},
            leeway=5  # 5 seconds leeway
        )
        print("This JWT token was signed by {} and was issued on {}".format(decoded['iss'], decoded['iat']))
    except Exception as e:
        json_data = json.dumps({'error': str(e)})

        print(json_data)

